          className="block w-full h-full cursor-zoom-in group"
          title="點擊放大"
        >
          <img
            src="/mtr-map.webp"
            alt="北部都會區交通及創科地圖"
            className="w-full h-full object-contain object-right"
          />
          {/* gradient fade on left edge so text stays readable */}
